#include "VivadoTCLGenerator.h"

#include <fstream>

#include "FlowManager.h"

#include "VivadoPaths.h"

#include "ProjectTarget.h"

#include "Panic.h"

using namespace stargate;

static const std::string SYNTH_TCL_NAME = "synth.tcl";
static const std::string IMPL_TCL_NAME = "impl.tcl";
static const std::string BITSTREAM_TCL_NAME = "bitstream.tcl";

static const std::string SYNTH_REPORT_UTIL = "synth_utilization.rpt";
static const std::string SYNTH_REPORT_TIMING = "synth_timing.rpt";

static const std::string IMPL_REPORT_UTIL = "impl_utilization.rpt";
static const std::string IMPL_REPORT_TIMING = "impl_timing.rpt";
static const std::string IMPL_REPORT_DRC = "impl_drc.rpt";

static const std::string BITSTREAM_EXTENSION = ".bit";

static const std::string TCL_BANNER =
    "# Auto-generated by stargate. Do not edit.\n";

VivadoTCLGenerator::VivadoTCLGenerator(const FlowManager* manager,
                                       const ProjectTarget* target)
    : _manager(manager),
    _target(target)
{
}

VivadoTCLGenerator::~VivadoTCLGenerator() {
}

void VivadoTCLGenerator::requireTop() const {
    if (_target->getTopModule().empty()) {
        panic("Target '{}' must specify 'top' for the vivado flow",
              _target->getName());
    }
}

void VivadoTCLGenerator::requirePart() const {
    if (_target->getPart().empty()) {
        panic("Target '{}' must specify 'part' for the vivado flow",
              _target->getName());
    }
}

void VivadoTCLGenerator::writeSynthTcl(const std::string& outputDir) {
    requireTop();
    requirePart();

    std::string fileListPath;
    VivadoPaths::getFileListPath(_manager, _target, fileListPath);

    std::string synthDcpPath;
    VivadoPaths::getSynthCheckpoint(_manager, synthDcpPath);

    const std::string tclPath = outputDir + "/" + SYNTH_TCL_NAME;
    const std::string utilReportPath = outputDir + "/" + SYNTH_REPORT_UTIL;
    const std::string timingReportPath = outputDir + "/" + SYNTH_REPORT_TIMING;

    std::ofstream out(tclPath);
    if (!out) {
        panic("Failed to open synth.tcl for writing: {}", tclPath);
    }

    out << TCL_BANNER;
    out << "# Vivado synthesis script for target '"
        << _target->getName() << "'\n\n";

    out << "set sg_top   " << _target->getTopModule() << "\n";
    out << "set sg_part  " << _target->getPart()      << "\n";
    out << "set sg_files " << fileListPath            << "\n";
    out << "set sg_dcp   " << synthDcpPath            << "\n";
    out << "set sg_util  " << utilReportPath          << "\n";
    out << "set sg_tim   " << timingReportPath        << "\n\n";

    out << "set sg_fp [open $sg_files r]\n";
    out << "while {[gets $sg_fp sg_line] >= 0} {\n";
    out << "    set sg_line [string trim $sg_line]\n";
    out << "    if {$sg_line eq \"\"} { continue }\n";
    out << "    set sg_ext [string tolower [file extension $sg_line]]\n";
    out << "    switch -- $sg_ext {\n";
    out << "        .v   { read_verilog $sg_line }\n";
    out << "        .vh  { read_verilog $sg_line }\n";
    out << "        .sv  { read_verilog -sv $sg_line }\n";
    out << "        .svh { read_verilog -sv $sg_line }\n";
    out << "        .vhd  -\n";
    out << "        .vhdl { read_vhdl $sg_line }\n";
    out << "        .xdc -\n";
    out << "        .sdc { read_xdc $sg_line }\n";
    out << "        .tcl { source $sg_line }\n";
    out << "        default {\n";
    out << "            puts \"stargate: skipping unknown file type: $sg_line\"\n";
    out << "        }\n";
    out << "    }\n";
    out << "}\n";
    out << "close $sg_fp\n\n";

    out << "synth_design -top $sg_top -part $sg_part\n";
    out << "write_checkpoint -force $sg_dcp\n";
    out << "report_utilization -file $sg_util\n";
    out << "report_timing_summary -file $sg_tim\n";
}

void VivadoTCLGenerator::writeImplTcl(const std::string& outputDir) {
    std::string synthDcpPath;
    VivadoPaths::getSynthCheckpoint(_manager, synthDcpPath);

    std::string implDcpPath;
    VivadoPaths::getImplCheckpoint(_manager, implDcpPath);

    const std::string tclPath = outputDir + "/" + IMPL_TCL_NAME;
    const std::string utilReportPath = outputDir + "/" + IMPL_REPORT_UTIL;
    const std::string timingReportPath = outputDir + "/" + IMPL_REPORT_TIMING;
    const std::string drcReportPath = outputDir + "/" + IMPL_REPORT_DRC;

    std::ofstream out(tclPath);
    if (!out) {
        panic("Failed to open impl.tcl for writing: {}", tclPath);
    }

    out << TCL_BANNER;
    out << "# Vivado implementation script for target '"
        << _target->getName() << "'\n\n";

    out << "set sg_synth_dcp " << synthDcpPath      << "\n";
    out << "set sg_impl_dcp  " << implDcpPath       << "\n";
    out << "set sg_util      " << utilReportPath    << "\n";
    out << "set sg_tim       " << timingReportPath  << "\n";
    out << "set sg_drc       " << drcReportPath     << "\n\n";

    out << "open_checkpoint $sg_synth_dcp\n";
    out << "opt_design\n";
    out << "place_design\n";
    out << "phys_opt_design\n";
    out << "route_design\n";
    out << "write_checkpoint -force $sg_impl_dcp\n";
    out << "report_utilization -file $sg_util\n";
    out << "report_timing_summary -file $sg_tim\n";
    out << "report_drc -file $sg_drc\n";
}

void VivadoTCLGenerator::writeBitstreamTcl(const std::string& outputDir) {
    requireTop();

    std::string implDcpPath;
    VivadoPaths::getImplCheckpoint(_manager, implDcpPath);

    const std::string tclPath = outputDir + "/" + BITSTREAM_TCL_NAME;
    const std::string bitPath =
        outputDir + "/" + _target->getTopModule() + BITSTREAM_EXTENSION;

    std::ofstream out(tclPath);
    if (!out) {
        panic("Failed to open bitstream.tcl for writing: {}", tclPath);
    }

    out << TCL_BANNER;
    out << "# Vivado bitstream script for target '"
        << _target->getName() << "'\n\n";

    out << "set sg_impl_dcp " << implDcpPath << "\n";
    out << "set sg_bit      " << bitPath     << "\n\n";

    out << "open_checkpoint $sg_impl_dcp\n";
    out << "write_bitstream -force $sg_bit\n";
}
